  --popover: hsl(100, 15%, 12%);
  --popover-foreground: hsl(40, 30%, 95%);
  --primary: hsl(95, 55%, 35%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(68, 45%, 45%);
  --secondary-foreground: hsl(100, 20%, 8%);
  --muted: hsl(120, 10%, 25%);
  --muted-foreground: hsl(100, 15%, 60%);
  --accent: hsl(30, 45%, 35%);
  --accent-foreground: hsl(40, 30%, 95%);
  --destructive: hsl(15, 75%, 50%);
  --destructive-foreground: hsl(0, 0%, 100%);
  --border: hsl(120, 15%, 20%);
  --input: hsl(120, 15%, 20%);
  --ring: hsl(95, 55%, 35%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground font-sans antialiased;
  }

  /* Custom scrollbar */
  ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }

  ::-webkit-scrollbar-track {
    background-color: hsl(var(--muted) / 0.2);
  }

  ::-webkit-scrollbar-thumb {
    @apply bg-muted rounded;
  }

  ::-webkit-scrollbar-thumb:hover {
    background-color: hsl(var(--muted) / 0.8);
  }
}

@layer components {
  .chart-bar {
    @apply transition-all duration-300 hover:opacity-80;
  }

  .sidebar-link {
    @apply flex items-center gap-3 px-4 py-3 rounded-lg transition-colors;
  }

  .sidebar-link.active {
    @apply text-primary font-medium;
    background-color: hsl(var(--primary) / 0.1);
  }

  .sidebar-link:not(.active) {
    @apply text-foreground;
  }

  .sidebar-link:not(.active):hover {
    background-color: hsl(var(--muted) / 0.2);
  }

  .metric-card {
    @apply bg-card rounded-lg border border-border p-6 hover:shadow-md transition-shadow;
  }

  .transaction-row {
    @apply border-b transition-colors;
    border-color: hsl(var(--border) / 0.5);
  }

  .transaction-row:hover {
    background-color: hsl(var(--muted) / 0.05);
  }
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-slide-in {
  animation: slideIn 0.3s ease-out;
}

