  // Documents
  async getDocuments(companyId: string): Promise<Document[]> {
    return Array.from(this.documents.values())
      .filter(d => d.companyId === companyId)
      .sort((a, b) => 
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
  }

