import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { X, Save, Upload, FileText } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { insertTransactionSchema, type InsertTransaction } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";
import { useCategories } from "@/hooks/use-categories";

// Form type with date as string for HTML date input
type TransactionFormData = Omit<InsertTransaction, 'date'> & { date: string };

interface TransactionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (transaction: InsertTransaction) => void;
  clients: Array<{ id: string; name: string }>;
  suppliers: Array<{ id: string; name: string }>;
  initialData?: any;
  mode?: 'create' | 'edit';
  fixedType?: 'income' | 'expense'; // Fixed transaction type from the calling page
}

export default function TransactionModal({ 
  isOpen, 
  onClose, 
  onSubmit, 
  clients = [], 
  suppliers = [],
  initialData = null,
  mode = 'create',
  fixedType
}: TransactionModalProps) {
  const { toast } = useToast();
  // Use fixedType if provided, otherwise use initialData type or default to 'income'
  const [transactionType, setTransactionType] = useState<'income' | 'expense'>(
    fixedType || initialData?.type || 'income'
  );
  const [selectedPdf, setSelectedPdf] = useState<{ name: string; data: string } | null>(
    initialData?.pdfFileName ? { name: initialData.pdfFileName, data: initialData.pdfDocument } : null
  );

  const { categories: incomeCategories } = useCategories('income');
  const { categories: expenseCategories } = useCategories('expense');

  // Form validation schema with date as string
  const formSchema = insertTransactionSchema.extend({
    date: z.string().min(1, "La fecha es obligatoria"),
    concept: z.string().min(1, "El concepto es obligatorio"),
    category: z.string().min(1, "La categoría es obligatoria"),
    amount: z.string().min(1, "El importe es obligatorio").refine(val => parseFloat(val) > 0, "El importe debe ser mayor a 0"),
  }).omit({ date: true }).merge(z.object({ date: z.string() }));

  const form = useForm<TransactionFormData>({
    resolver: zodResolver(formSchema),
    defaultValues: initialData ? {
      type: fixedType || initialData.type,
      date: new Date(initialData.date).toISOString().split('T')[0],
      concept: initialData.concept,
      category: initialData.category,
      amount: String(initialData.amount),
      quantity: initialData.quantity || '',
      clientSupplierId: initialData.clientSupplierId || '',
      notes: initialData.notes || '',
      pdfDocument: initialData.pdfDocument || '',
      pdfFileName: initialData.pdfFileName || '',
    } : {
      type: fixedType || 'income',
      date: new Date().toISOString().split('T')[0],
      concept: '',
      category: '',
      amount: '0',
      quantity: '',
      clientSupplierId: '',
      notes: '',
      pdfDocument: '',
      pdfFileName: '',
    },
  });

  const handlePdfChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        toast({
          title: "Error",
          description: "Solo se permiten archivos PDF.",
          variant: "destructive",
        });
        return;
      }

      const reader = new FileReader();
      reader.onload = () => {
        const base64 = reader.result as string;
        setSelectedPdf({ name: file.name, data: base64 });
        form.setValue('pdfDocument', base64);
        form.setValue('pdfFileName', file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemovePdf = () => {
    setSelectedPdf(null);
    form.setValue('pdfDocument', '');
    form.setValue('pdfFileName', '');
  };

  useEffect(() => {
    if (initialData) {
      const typeToUse = fixedType || initialData.type;
      form.reset({
        type: typeToUse,
        date: new Date(initialData.date).toISOString().split('T')[0],
        concept: initialData.concept,
        category: initialData.category,
        amount: String(initialData.amount),
        quantity: initialData.quantity || '',
        clientSupplierId: initialData.clientSupplierId || '',
        notes: initialData.notes || '',
        pdfDocument: initialData.pdfDocument || '',
        pdfFileName: initialData.pdfFileName || '',
      });
      setTransactionType(typeToUse);
      if (initialData.pdfFileName) {
        setSelectedPdf({ name: initialData.pdfFileName, data: initialData.pdfDocument });
      }
    } else {
      const typeToUse = fixedType || 'income';
      form.reset({
        type: typeToUse,
        date: new Date().toISOString().split('T')[0],
        concept: '',
        category: '',
        amount: '0',
        quantity: '',
        clientSupplierId: '',
        notes: '',
        pdfDocument: '',
        pdfFileName: '',
      });
      setTransactionType(typeToUse);
      setSelectedPdf(null);
    }
  }, [initialData, form, fixedType]);

  const handleSubmit = (data: TransactionFormData) => {
    try {
      // Convert string date to Date object and ensure amount is a string
      const formattedData: InsertTransaction = {
        ...data,
        amount: String(data.amount),
        date: new Date(data.date),
        clientSupplierId: data.clientSupplierId || undefined,
      };
      onSubmit(formattedData);

      // Reset form with the correct type based on fixedType
      const typeToUse = fixedType || 'income';
      form.reset({
        type: typeToUse,
        date: new Date().toISOString().split('T')[0],
        concept: '',
        category: '',
        amount: '0',
        quantity: '',
        clientSupplierId: '',
        notes: '',
        pdfDocument: '',
        pdfFileName: '',
      });
      setTransactionType(typeToUse);
      setSelectedPdf(null);
      onClose();
      toast({
        title: "Transacción creada",
        description: "La transacción se ha registrado correctamente.",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "No se pudo crear la transacción. Intenta nuevamente.",
        variant: "destructive",
      });
    }
  };

  const handleTypeChange = (type: string) => {
    setTransactionType(type as 'income' | 'expense');
    form.setValue('type', type as 'income' | 'expense');
    form.setValue('category', '');
  };

  const activeIncomeCategories = incomeCategories?.filter(cat => cat.isActive) || [];
  const activeExpenseCategories = expenseCategories?.filter(cat => cat.isActive) || [];
  const currentCategories = transactionType === 'income' ? activeIncomeCategories : activeExpenseCategories;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{mode === 'edit' ? 'Editar Transacción' : 'Nueva Transacción'}</DialogTitle>
        </DialogHeader>

        <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6" data-testid="transaction-form">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <Label htmlFor="type">Tipo de Transacción</Label>
              <Select 
                onValueChange={handleTypeChange} 
                value={transactionType}
                disabled={!!fixedType}
              >
                <SelectTrigger data-testid="select-transaction-type" disabled={!!fixedType}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="income">Ingreso</SelectItem>
                  <SelectItem value="expense">Gasto</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="date">Fecha</Label>
              <Input
                type="date"
                {...form.register("date")}
                data-testid="input-date"
              />
            </div>
          </div>

          <div>
            <Label htmlFor="concept">Concepto</Label>
            <Input
              placeholder="Ej: Venta de maíz, Compra de fertilizantes..."
              {...form.register("concept")}
              data-testid="input-concept"
            />
            {form.formState.errors.concept && (
              <p className="text-sm text-destructive mt-1">
                {form.formState.errors.concept.message}
              </p>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <Label htmlFor="category">Categoría</Label>
              <Select 
                onValueChange={(value) => form.setValue('category', value)}
                value={form.watch('category') || undefined}
              >
                <SelectTrigger data-testid="select-category">
                  <SelectValue placeholder="Seleccionar categoría" />
                </SelectTrigger>
                <SelectContent>
                  {currentCategories.map((category) => (
                    <SelectItem key={category.id} value={category.name}>
                      {category.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {form.formState.errors.category && (
                <p className="text-sm text-destructive mt-1">
                  {form.formState.errors.category.message}
                </p>
              )}
            </div>

            <div>
              <Label htmlFor="amount">Importe</Label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground">€</span>
                <Input
                  type="number"
                  step="0.01"
                  placeholder="0.00"
                  className="pl-8"
                  {...form.register("amount")}
                  data-testid="input-amount"
                />
              </div>
              {form.formState.errors.amount && (
                <p className="text-sm text-destructive mt-1">
                  {form.formState.errors.amount.message}
                </p>
              )}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <Label htmlFor="quantity">Cantidad (opcional)</Label>
              <Input
                placeholder="Ej: 2500 kg, 150 unidades..."
                {...form.register("quantity")}
                data-testid="input-quantity"
              />
            </div>

            <div>
              <Label htmlFor="clientSupplierId">
                {transactionType === 'income' ? 'Cliente' : 'Proveedor'} (opcional)
              </Label>
              <Select 
                onValueChange={(value) => form.setValue('clientSupplierId', value || undefined)}
                value={form.watch('clientSupplierId') || undefined}
              >
                <SelectTrigger data-testid="select-client-supplier">
                  <SelectValue placeholder="Seleccionar" />
                </SelectTrigger>
                <SelectContent>
                  {(transactionType === 'income' ? clients : suppliers).map((entity) => (
                    <SelectItem key={entity.id} value={entity.id}>
                      {entity.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div>
            <Label htmlFor="notes">Notas adicionales (opcional)</Label>
            <Textarea
              rows={3}
              placeholder="Detalles adicionales sobre la transacción..."
              className="resize-none"
              {...form.register("notes")}
              data-testid="textarea-notes"
            />
          </div>

          <div>
            <Label htmlFor="pdf">Documento PDF (opcional)</Label>
            <div className="mt-2">
              {!selectedPdf ? (
                <div className="flex items-center gap-3">
                  <Input
                    id="pdf"
                    type="file"
                    accept=".pdf,application/pdf"
                    onChange={handlePdfChange}
                    className="hidden"
                    data-testid="input-pdf-file"
                  />
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => document.getElementById('pdf')?.click()}
                    className="w-full"
                    data-testid="button-upload-pdf"
                  >
                    <Upload className="w-4 h-4 mr-2" />
                    Seleccionar archivo PDF
                  </Button>
                </div>
              ) : (
                <div className="flex items-center gap-3 p-3 bg-muted rounded-md" data-testid="pdf-preview">
                  <FileText className="w-5 h-5 text-primary" />
                  <span className="flex-1 text-sm truncate" data-testid="text-pdf-name">
                    {selectedPdf.name}
                  </span>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={handleRemovePdf}
                    data-testid="button-remove-pdf"
                  >
                    <X className="w-4 h-4" />
                  </Button>
                </div>
              )}
            </div>
          </div>

          <div className="flex items-center gap-3 pt-6 border-t border-border">
            <Button type="submit" className="flex-1" data-testid="button-save-transaction">
              <Save className="w-4 h-4 mr-2" />
              Guardar Transacción
            </Button>
            <Button type="button" variant="outline" onClick={onClose} data-testid="button-cancel-transaction">
              Cancelar
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ui/sidebar.tsx.content:
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { VariantProps, cva } from "class-variance-authority"
import { PanelLeft } from "lucide-react"

import { useIsMobile } from "@/hooks/use-mobile"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Separator } from "@/components/ui/separator"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import { Skeleton } from "@/components/ui/skeleton"
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip"

const SIDEBAR_COOKIE_NAME = "sidebar_state"
const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7
const SIDEBAR_WIDTH = "16rem"
const SIDEBAR_WIDTH_MOBILE = "18rem"
const SIDEBAR_WIDTH_ICON = "3rem"
const SIDEBAR_KEYBOARD_SHORTCUT = "b"

type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)

function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }

  return context
}

const SidebarProvider = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    defaultOpen?: boolean
    open?: boolean
    onOpenChange?: (open: boolean) => void
  }
>(
  (
    {
      defaultOpen = true,
      open: openProp,
      onOpenChange: setOpenProp,
      className,
      style,
      children,
      ...props
    },
    ref
  ) => {
    const isMobile = useIsMobile()
    const [openMobile, setOpenMobile] = React.useState(false)

    // This is the internal state of the sidebar.
    // We use openProp and setOpenProp for control from outside the component.
    const [_open, _setOpen] = React.useState(defaultOpen)
    const open = openProp ?? _open
    const setOpen = React.useCallback(
      (value: boolean | ((value: boolean) => boolean)) => {
        const openState = typeof value === "function" ? value(open) : value
        if (setOpenProp) {
          setOpenProp(openState)
        } else {
          _setOpen(openState)
        }

        // This sets the cookie to keep the sidebar state.
        document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`
      },
      [setOpenProp, open]
    )

    // Helper to toggle the sidebar.
    const toggleSidebar = React.useCallback(() => {
      return isMobile
        ? setOpenMobile((open) => !open)
        : setOpen((open) => !open)
    }, [isMobile, setOpen, setOpenMobile])

    // Adds a keyboard shortcut to toggle the sidebar.
    React.useEffect(() => {
      const handleKeyDown = (event: KeyboardEvent) => {
        if (
          event.key === SIDEBAR_KEYBOARD_SHORTCUT &&
          (event.metaKey || event.ctrlKey)
        ) {
          event.preventDefault()
          toggleSidebar()
        }
      }

      window.addEventListener("keydown", handleKeyDown)
      return () => window.removeEventListener("keydown", handleKeyDown)
    }, [toggleSidebar])

    // We add a state so that we can do data-state="expanded" or "collapsed".
    // This makes it easier to style the sidebar with Tailwind classes.
    const state = open ? "expanded" : "collapsed"

    const contextValue = React.useMemo<SidebarContextProps>(
      () => ({
        state,
        open,
        setOpen,
        isMobile,
        openMobile,
        setOpenMobile,
        toggleSidebar,
      }),
      [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
    )

    return (
      <SidebarContext.Provider value={contextValue}>
        <TooltipProvider delayDuration={0}>
          <div
            style={
              {
                "--sidebar-width": SIDEBAR_WIDTH,
                "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
                ...style,
              } as React.CSSProperties
            }
            className={cn(
              "group/sidebar-wrapper flex min-h-svh w-full has-[[data-variant=inset]]:bg-sidebar",
              className
            )}
            ref={ref}
            {...props}
          >
            {children}
          </div>
        </TooltipProvider>
      </SidebarContext.Provider>
    )
  }
)
SidebarProvider.displayName = "SidebarProvider"

const Sidebar = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    side?: "left" | "right"
    variant?: "sidebar" | "floating" | "inset"
    collapsible?: "offcanvas" | "icon" | "none"
  }
>(
  (
    {
      side = "left",
      variant = "sidebar",
      collapsible = "offcanvas",
      className,
      children,
      ...props
    },
    ref
  ) => {
    const { isMobile, state, openMobile, setOpenMobile } = useSidebar()

    if (collapsible === "none") {
      return (
        <div
          className={cn(
            "flex h-full w-[--sidebar-width] flex-col bg-sidebar text-sidebar-foreground",
            className
          )}
          ref={ref}
          {...props}
        >
          {children}
        </div>
      )
    }

    if (isMobile) {
      return (
        <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
          <SheetContent
            data-sidebar="sidebar"
            data-mobile="true"
            className="w-[--sidebar-width] bg-sidebar p-0 text-sidebar-foreground [&>button]:hidden"
            style={
              {
                "--sidebar-width": SIDEBAR_WIDTH_MOBILE,
              } as React.CSSProperties
            }
            side={side}
          >
            <SheetHeader className="sr-only">
              <SheetTitle>Sidebar</SheetTitle>
              <SheetDescription>Displays the mobile sidebar.</SheetDescription>
            </SheetHeader>
            <div className="flex h-full w-full flex-col">{children}</div>
          </SheetContent>
        </Sheet>
      )
    }

    return (
      <div
        ref={ref}
        className="group peer hidden text-sidebar-foreground md:block"
        data-state={state}
        data-collapsible={state === "collapsed" ? collapsible : ""}
        data-variant={variant}
        data-side={side}
      >
        {/* This is what handles the sidebar gap on desktop */}
        <div
          className={cn(
            "relative w-[--sidebar-width] bg-transparent transition-[width] duration-200 ease-linear",
            "group-data-[collapsible=offcanvas]:w-0",
            "group-data-[side=right]:rotate-180",
            variant === "floating" || variant === "inset"
              ? "group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)_+_theme(spacing.4))]"
              : "group-data-[collapsible=icon]:w-[--sidebar-width-icon]"
          )}
        />
        <div
          className={cn(
            "fixed inset-y-0 z-10 hidden h-svh w-[--sidebar-width] transition-[left,right,width] duration-200 ease-linear md:flex",
            side === "left"
              ? "left-0 group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)]"
              : "right-0 group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)]",
            // Adjust the padding for floating and inset variants.
            variant === "floating" || variant === "inset"
              ? "p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)_+_theme(spacing.4)_+2px)]"
              : "group-data-[collapsible=icon]:w-[--sidebar-width-icon] group-data-[side=left]:border-r group-data-[side=right]:border-l",
            className
          )}
          {...props}
        >
          <div
            data-sidebar="sidebar"
            className="flex h-full w-full flex-col bg-sidebar group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:border-sidebar-border group-data-[variant=floating]:shadow"
          >
            {children}
          </div>
        </div>
      </div>
    )
  }
)
Sidebar.displayName = "Sidebar"

const SidebarTrigger = React.forwardRef<
  React.ElementRef<typeof Button>,
  React.ComponentProps<typeof Button>
>(({ className, onClick, ...props }, ref) => {
  const { toggleSidebar } = useSidebar()

  return (
    <Button
      ref={ref}
      data-sidebar="trigger"
      variant="ghost"
      size="icon"
      className={cn("h-7 w-7", className)}
      onClick={(event) => {
        onClick?.(event)
        toggleSidebar()
      }}
      {...props}
    >
      <PanelLeft />
      <span className="sr-only">Toggle Sidebar</span>
    </Button>
  )
})
SidebarTrigger.displayName = "SidebarTrigger"

const SidebarRail = React.forwardRef<
