import { useState } from "react";
import { Plus, Edit, Trash2, FileText } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Switch } from "@/components/ui/switch";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import Sidebar from "@/components/layout/Sidebar";
import MobileMenu from "@/components/layout/MobileMenu";
import TopBar from "@/components/layout/TopBar";
import { useDocumentCategories } from "@/hooks/use-document-categories";
import { useCompanyPermission } from "@/hooks/use-company-permission";
import NoCompanySelected from "@/components/shared/NoCompanySelected";
import { insertDocumentCategorySchema, type InsertDocumentCategory } from "@shared/schema";

type CategoryFormValues = InsertDocumentCategory;

export default function DocumentCategories() {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<string | null>(null);

  const { categories, createCategory, updateCategory, deleteCategory, isLoading } = useDocumentCategories();
  const { canWrite, hasCompanySelected } = useCompanyPermission();

  const form = useForm<CategoryFormValues>({
    resolver: zodResolver(insertDocumentCategorySchema),
    defaultValues: {
      name: '',
      description: '',
      isActive: true,
    },
  });

  const handleSubmit = (data: CategoryFormValues) => {
    if (editingCategory) {
      updateCategory.mutate({ id: editingCategory, category: data });
    } else {
      createCategory.mutate(data);
    }
    handleCloseModal();
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingCategory(null);
    form.reset({
      name: '',
      description: '',
      isActive: true,
    });
  };

  const handleEdit = (categoryId: string) => {
    const category = categories?.find(c => c.id === categoryId);
    if (category) {
      setEditingCategory(categoryId);
      form.reset({
        name: category.name,
        description: category.description || '',
        isActive: category.isActive,
      });
      setIsModalOpen(true);
    }
  };

  const handleDelete = (categoryId: string) => {
    if (window.confirm('¿Está seguro de que desea eliminar esta categoría de documentos?')) {
      deleteCategory.mutate(categoryId);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-background">
      <Sidebar />
      <MobileMenu isOpen={isMobileMenuOpen} onClose={() => setIsMobileMenuOpen(false)} />

      {!hasCompanySelected ? (
        <div className="flex-1 flex items-center justify-center">
          <NoCompanySelected />
        </div>
      ) : isLoading ? (
        <div className="flex-1 flex items-center justify-center">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
            <p className="text-muted-foreground">Cargando categorías de documentos...</p>
          </div>
        </div>
      ) : (
        <main className="flex-1 overflow-y-auto">
          <TopBar
            title="Categorías de Documentos"
            subtitle="Gestión de categorías para documentos"
            onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
          />

          <div className="p-4 lg:p-8">
            <div className="bg-card rounded-lg border border-border p-6">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-lg font-semibold text-foreground">Categorías de Documentos</h3>
                <p className="text-sm text-muted-foreground">
                  {categories?.length || 0} categorías registradas
                </p>
              </div>
              <Button 
                onClick={() => setIsModalOpen(true)}
                data-testid="button-add-document-category"
                disabled={!canWrite}
              >
                <Plus className="w-4 h-4 mr-2" />
                Agregar Categoría
              </Button>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3" data-testid="document-categories-list">
              {categories?.map((category) => (
                <div
                  key={category.id}
                  className="bg-muted/50 rounded-lg p-4 border border-border hover:border-primary/50 transition-colors"
                  data-testid={`document-category-card-${category.id}`}
                >
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-blue-500/20 flex items-center justify-center">
                        <FileText className="w-5 h-5 text-blue-600" />
                      </div>
                      <div className="flex-1">
                        <h4 className="font-medium text-foreground" data-testid={`document-category-name-${category.id}`}>
                          {category.name}
                        </h4>
                        <p className="text-sm text-muted-foreground">
                          {category.isActive ? 'Activa' : 'Inactiva'}
                        </p>
                      </div>
                    </div>
                  </div>

                  {category.description && (
                    <p className="text-sm text-muted-foreground mb-3 line-clamp-2">
                      {category.description}
                    </p>
                  )}

                  <div className="flex gap-2">
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => handleEdit(category.id)}
                      data-testid={`button-edit-document-category-${category.id}`}
                      disabled={!canWrite}
                    >
                      <Edit className="w-4 h-4 mr-1" />
                      Editar
                    </Button>
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => handleDelete(category.id)}
                      data-testid={`button-delete-document-category-${category.id}`}
                      disabled={!canWrite}
                    >
                      <Trash2 className="w-4 h-4 mr-1" />
                      Eliminar
                    </Button>
                  </div>
                </div>
              ))}
            </div>
            </div>
          </div>
        </main>
      )}

      <Dialog open={isModalOpen} onOpenChange={handleCloseModal}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingCategory ? 'Editar Categoría de Documento' : 'Nueva categoría de documento'}
            </DialogTitle>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-4">
              <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nombre de la Categoría</FormLabel>
                    <FormControl>
                      <Input 
                        {...field} 
                        placeholder="Ej: Contratos, Facturas, Certificados"
                        data-testid="input-document-category-name"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="description"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Descripción (opcional)</FormLabel>
                    <FormControl>
                      <Textarea 
                        {...field} 
                        value={field.value || ''}
                        placeholder="Descripción de la categoría"
                        data-testid="input-document-category-description"
                        rows={3}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="isActive"
                render={({ field }) => (
                  <FormItem className="flex items-center justify-between rounded-lg border p-4">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base">Estado</FormLabel>
                      <div className="text-sm text-muted-foreground">
                        {field.value ? 'Categoría activa' : 'Categoría inactiva'}
                      </div>
                    </div>
                    <FormControl>
                      <Switch
                        checked={field.value}
                        onCheckedChange={field.onChange}
                        data-testid="switch-document-category-active"
                      />
                    </FormControl>
                  </FormItem>
                )}
              />

              <div className="flex justify-end gap-2">
                <Button 
                  type="button" 
                  variant="outline" 
                  onClick={handleCloseModal}
                  data-testid="button-cancel"
                >
                  Cancelar
                </Button>
                <Button 
                  type="submit"
                  disabled={createCategory.isPending || updateCategory.isPending}
                  data-testid="button-save-document-category"
                >
                  {editingCategory ? 'Actualizar' : 'Crear'}
                </Button>
              </div>
            </form>
          </Form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/components/shared/PdfViewer.t.content:
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Download, X } from "lucide-react";

interface PdfViewerProps {
  isOpen: boolean;
  onClose: () => void;
  pdfData: string;
  fileName: string;
}

export default function PdfViewer({ isOpen, onClose, pdfData, fileName }: PdfViewerProps) {
  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = pdfData;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-5xl h-[90vh] flex flex-col">
        <DialogHeader className="flex-shrink-0">
          <div className="flex items-center justify-between">
            <DialogTitle>{fileName}</DialogTitle>
            <div className="flex items-center gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleDownload}
                data-testid="button-download-pdf"
              >
                <Download className="h-4 w-4 mr-2" />
                Descargar
              </Button>
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-hidden rounded-md border border-border bg-muted/30">
          <iframe
            src={pdfData}
            className="w-full h-full"
            title={fileName}
            data-testid="pdf-iframe"
          />
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/hooks/use-document-categories.content:
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { type DocumentCategory, type InsertDocumentCategory } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";
import { useCompany } from "@/contexts/CompanyContext";

export function useDocumentCategories() {
  const { toast } = useToast();
  const { currentCompanyId } = useCompany();

  const { data: categories, isLoading } = useQuery<DocumentCategory[]>({
    queryKey: ['/api/document-categories', { companyId: currentCompanyId }],
    queryFn: async () => {
      const params = new URLSearchParams();
      if (currentCompanyId) params.append('companyId', currentCompanyId);
      const url = `/api/document-categories?${params.toString()}`;
      const res = await fetch(url, { credentials: "include" });
      if (!res.ok) {
        throw new Error(`${res.status}: ${res.statusText}`);
      }
      return await res.json();
    },
    enabled: !!currentCompanyId,
  });

  const createCategory = useMutation({
    mutationFn: async (category: InsertDocumentCategory) => {
      const response = await apiRequest('POST', '/api/document-categories', {
        ...category,
        companyId: currentCompanyId,
      });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ['/api/document-categories', { companyId: currentCompanyId }],
        exact: false,
        refetchType: 'all'
      });
      toast({
        title: "Categoría creada",
        description: "La categoría de documento se ha creado correctamente",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo crear la categoría de documento",
        variant: "destructive",
      });
    },
  });

  const updateCategory = useMutation({
    mutationFn: async ({ id, category }: { id: string; category: Partial<InsertDocumentCategory> }) => {
      const response = await apiRequest('PUT', `/api/document-categories/${id}`, { ...category, companyId: currentCompanyId ?? undefined });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ['/api/document-categories', { companyId: currentCompanyId }],
        exact: false,
        refetchType: 'all'
      });
      toast({
        title: "Categoría actualizada",
        description: "La categoría de documento se ha actualizado correctamente",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo actualizar la categoría de documento",
        variant: "destructive",
      });
    },
  });

  const deleteCategory = useMutation({
    mutationFn: async (id: string) => {
      const params = new URLSearchParams();
      if (currentCompanyId) params.append('companyId', currentCompanyId);
      await apiRequest('DELETE', `/api/document-categories/${id}?${params.toString()}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ['/api/document-categories', { companyId: currentCompanyId }],
        exact: false,
        refetchType: 'all'
      });
      toast({
        title: "Categoría eliminada",
        description: "La categoría de documento se ha eliminado correctamente",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo eliminar la categoría de documento",
        variant: "destructive",
      });
    },
  });

  return {
    categories,
    createCategory,
    updateCategory,
    deleteCategory,
    isLoading,
  };
}

client/src/pages/Events.tsx.content:
import { useState, useMemo } from "react";
import { Plus, Calendar, Edit, Trash2, Search, Check, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import Sidebar from "@/components/layout/Sidebar";
import MobileMenu from "@/components/layout/MobileMenu";
import TopBar from "@/components/layout/TopBar";
import { useEvents } from "@/hooks/use-events";
import { useCompanyPermission } from "@/hooks/use-company-permission";
import { useCompany } from "@/contexts/CompanyContext";
import NoCompanySelected from "@/components/shared/NoCompanySelected";
import { insertEventSchema, type InsertEvent } from "@shared/schema";
import { format } from "date-fns";
import { es } from "date-fns/locale";

export default function Events() {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingEvent, setEditingEvent] = useState<string | null>(null);
  const [searchFilter, setSearchFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'read'>('all');

  const { events, createEvent, updateEvent, deleteEvent, isLoading } = useEvents();
  const { canWrite, hasCompanySelected } = useCompanyPermission();
  const { currentCompanyId } = useCompany();

  const form = useForm<InsertEvent>({
    resolver: zodResolver(insertEventSchema),
    defaultValues: {
      date: new Date(),
      description: '',
    },
  });

  const filteredEvents = useMemo(() => {
    if (!events) return [];

    let filtered = events;

    // Filter by search
    if (searchFilter.trim()) {
      const searchLower = searchFilter.toLowerCase().trim();
      filtered = filtered.filter(event => 
        event.description.toLowerCase().includes(searchLower)
      );
    }

    // Filter by status
    if (statusFilter === 'pending') {
      filtered = filtered.filter(event => !event.isRead);
    } else if (statusFilter === 'read') {
      filtered = filtered.filter(event => event.isRead);
    }

    return filtered;
  }, [events, searchFilter, statusFilter]);

  const hasActiveFilters = searchFilter.trim() !== '' || statusFilter !== 'all';

  const clearFilters = () => {
    setSearchFilter('');
    setStatusFilter('all');
  };

  const handleSubmit = (data: InsertEvent) => {
    if (editingEvent) {
      updateEvent.mutate({ id: editingEvent, event: { ...data, companyId: currentCompanyId ?? undefined } });
    } else {
      createEvent.mutate({ ...data, companyId: currentCompanyId ?? undefined });
    }
    handleCloseModal();
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingEvent(null);
    form.reset({
      date: new Date(),
      description: '',
    });
  };

  const handleEdit = (eventId: string) => {
    const event = events?.find(e => e.id === eventId);
    if (event) {
      setEditingEvent(eventId);
      form.reset({
        date: new Date(event.date),
        description: event.description,
      });
      setIsModalOpen(true);
    }
  };

  const handleDelete = (eventId: string) => {
    if (window.confirm('¿Está seguro de que desea eliminar este evento?')) {
      deleteEvent.mutate(eventId);
    }
  };

  const formatDate = (date: Date | string) => {
    const dateObj = typeof date === 'string' ? new Date(date) : date;
    return format(dateObj, "dd 'de' MMMM 'de' yyyy", { locale: es });
  };

  return (
    <div className="flex h-screen overflow-hidden bg-background">
      <Sidebar />
      <MobileMenu isOpen={isMobileMenuOpen} onClose={() => setIsMobileMenuOpen(false)} />

      {!hasCompanySelected ? (
        <div className="flex-1 flex items-center justify-center">
          <NoCompanySelected />
        </div>
      ) : isLoading ? (
        <div className="flex-1 flex items-center justify-center">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
            <p className="text-muted-foreground">Cargando eventos...</p>
          </div>
        </div>
      ) : (
        <main className="flex-1 overflow-y-auto">
          <TopBar
            title="Eventos"
            subtitle="Gestión de eventos importantes"
            onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
          />

          <div className="p-4 lg:p-8">
            <div className="bg-card rounded-lg border border-border p-6">
              <div className="flex flex-col gap-4 mb-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-lg font-semibold text-foreground">Lista de Eventos</h3>
                    <p className="text-sm text-muted-foreground">
                      {filteredEvents.length} {filteredEvents.length === events?.length ? 'eventos registrados' : `de ${events?.length || 0} eventos`}
                    </p>
                  </div>
                  <Button 
                    onClick={() => setIsModalOpen(true)}
                    data-testid="button-add-event"
                    disabled={!canWrite}
                  >
                    <Plus className="w-4 h-4 mr-2" />
                    Agregar Evento
                  </Button>
                </div>

                {/* Filters */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="relative md:col-span-2">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                    <Input
                      placeholder="Buscar eventos por descripción..."
                      value={searchFilter}
                      onChange={(e) => setSearchFilter(e.target.value)}
                      className="pl-10"
                      data-testid="input-search-events"
                    />
                  </div>
                  <Select
                    value={statusFilter}
                    onValueChange={(value) => setStatusFilter(value as 'all' | 'pending' | 'read')}
                  >
                    <SelectTrigger data-testid="select-status-filter">
                      <SelectValue placeholder="Filtrar por estado" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">Todos los eventos</SelectItem>
                      <SelectItem value="pending">Pendientes</SelectItem>
                      <SelectItem value="read">Leídos</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                {/* Clear Filters Button */}
                {hasActiveFilters && (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={clearFilters}
                    className="w-fit"
                    data-testid="button-clear-filters"
                  >
                    <X className="w-4 h-4 mr-2" />
                    Limpiar filtros
                  </Button>
                )}
              </div>

              <div className="overflow-x-auto" data-testid="events-table">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-border">
                      <th className="text-left py-3 px-4 text-xs font-semibold text-muted-foreground uppercase">
                        Fecha
                      </th>
                      <th className="text-left py-3 px-4 text-xs font-semibold text-muted-foreground uppercase">
                        Descripción
                      </th>
                      <th className="text-center py-3 px-4 text-xs font-semibold text-muted-foreground uppercase">
                        Estado
                      </th>
                      <th className="text-center py-3 px-4 text-xs font-semibold text-muted-foreground uppercase">
                        Acciones
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {!filteredEvents || filteredEvents.length === 0 ? (
                      <tr>
                        <td colSpan={4} className="py-8 text-center text-muted-foreground">
                          {searchFilter ? 'No se encontraron eventos que coincidan con la búsqueda.' : 'No hay eventos registrados.'}
                          {!searchFilter && canWrite && (
                            <button 
                              onClick={() => setIsModalOpen(true)}
                              className="text-primary hover:underline ml-1"
                            >
                              Agregar el primero
                            </button>
                          )}
                        </td>
                      </tr>
                    ) : (
                      filteredEvents.map((event) => (
                        <tr 
                          key={event.id} 
                          className="transaction-row"
                          data-testid={`event-row-${event.id}`}
                        >
                          <td className="py-3 px-4">
                            <div className="flex items-center gap-2">
                              <Calendar className="w-4 h-4 text-primary" />
                              <span className="text-sm font-medium">
                                {formatDate(event.date)}
                              </span>
                            </div>
                          </td>
                          <td className="py-3 px-4">
                            <p className="text-sm text-foreground">{event.description}</p>
                          </td>
                          <td className="py-3 px-4">
                            <div className="flex items-center justify-center">
                              {event.isRead ? (
                                <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-muted text-muted-foreground">
                                  <Check className="w-3 h-3" />
                                  Leído
                                </span>
                              ) : (
                                <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-primary/10 text-primary">
                                  <Calendar className="w-3 h-3" />
                                  Pendiente
                                </span>
                              )}
                            </div>
                          </td>
                          <td className="py-3 px-4">
                            <div className="flex items-center justify-center gap-2">
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => handleEdit(event.id)}
                                disabled={!canWrite}
                                data-testid={`button-edit-event-${event.id}`}
                              >
                                <Edit className="w-4 h-4" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => handleDelete(event.id)}
                                disabled={!canWrite}
                                data-testid={`button-delete-event-${event.id}`}
                              >
                                <Trash2 className="w-4 h-4 text-destructive" />
                              </Button>
                            </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </main>
      )}

      {/* Modal */}
      <Dialog open={isModalOpen} onOpenChange={handleCloseModal}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>
              {editingEvent ? 'Editar Evento' : 'Nuevo Evento'}
            </DialogTitle>
          </DialogHeader>

          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-4" data-testid="event-form">
            <div>
              <Label htmlFor="date">Fecha del Evento *</Label>
              <Input
                id="date"
                type="date"
                value={form.watch('date') ? format(new Date(form.watch('date')), 'yyyy-MM-dd') : ''}
                onChange={(e) => {
                  const value = e.target.value;
                  form.setValue('date', value ? new Date(value) : new Date());
                }}
                data-testid="input-event-date"
              />
              {form.formState.errors.date && (
                <p className="text-sm text-destructive mt-1">
                  {form.formState.errors.date.message}
                </p>
              )}
            </div>

            <div>
              <Label htmlFor="description">Descripción *</Label>
              <Textarea
                id="description"
                {...form.register("description")}
                placeholder="Describe el evento..."
                rows={4}
                data-testid="input-event-description"
              />
              {form.formState.errors.description && (
                <p className="text-sm text-destructive mt-1">
                  {form.formState.errors.description.message}
                </p>
              )}
            </div>

            <div className="flex justify-end gap-2 pt-4">
              <Button
                type="button"
                variant="outline"
                onClick={handleCloseModal}
                data-testid="button-cancel-event"
              >
                Cancelar
              </Button>
              <Button 
                type="submit"
                data-testid="button-save-event"
              >
                {editingEvent ? 'Guardar Cambios' : 'Crear Evento'}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

